@page "/board"
@using sv_a21429226a954aa7b0d49bde9e75ee3c.Services
@inject ITaskService TaskService
@rendermode InteractiveServer

<PageTitle>Kanban Board</PageTitle>

<h1>Project Board</h1>

@if (_loading)
{
    <p><em>Loading tasks...</em></p>
}
else if (_error is not null)
{
    <div class="alert alert-danger">@_error</div>
}
else
{
    <!-- Stats Bar -->
    <div class="stats-bar d-flex gap-3 mb-3 p-2 bg-light rounded">
        <span><strong>Total:</strong> @_filteredTasks.Count</span>
        <span><strong>To Do:</strong> @GetColumnTasks("To Do").Count</span>
        <span><strong>In Progress:</strong> @GetColumnTasks("In Progress").Count</span>
        <span><strong>Done:</strong> @GetColumnTasks("Done").Count</span>
        <span class="text-danger"><strong>Overdue:</strong> @_filteredTasks.Count(t => t.DueDate < DateTime.Today)</span>
    </div>

    <!-- Search Bar -->
    <div class="mb-3">
        <input type="text" class="form-control" placeholder="Search tasks by title..."
               @bind="_searchTerm" @bind:event="oninput" />
    </div>

    <!-- Kanban Columns -->
    <div class="d-flex gap-3">
        @foreach (var column in _columns)
        {
            var tasks = GetColumnTasks(column);
            <div class="kanban-column flex-fill border rounded p-2" style="min-width: 250px;">
                <h5>@column <span class="badge bg-secondary">@tasks.Count</span></h5>

                @foreach (var task in tasks)
                {
                    <div class="card mb-2">
                        <div class="card-body p-2">
                            <h6 class="card-title mb-1">@task.Title</h6>
                            <p class="card-text mb-1 small text-muted">@task.Assignee</p>
                            <span class="badge @GetPriorityClass(task.Priority)">@task.Priority</span>
                            <span class="small ms-2">@task.DueDate.ToString("MMM dd")</span>
                            <div class="mt-2 d-flex gap-1">
                                @if (GetColumnIndex(column) > 0)
                                {
                                    <button class="btn btn-sm btn-outline-secondary"
                                            @onclick="() => MoveTask(task, -1)">Move Left</button>
                                }
                                @if (GetColumnIndex(column) < _columns.Length - 1)
                                {
                                    <button class="btn btn-sm btn-outline-secondary"
                                            @onclick="() => MoveTask(task, 1)">Move Right</button>
                                }
                            </div>
                        </div>
                    </div>
                }

                @if (_showForm == column)
                {
                    <div class="card mb-2 border-primary">
                        <div class="card-body p-2">
                            <input type="text" class="form-control form-control-sm mb-1"
                                   placeholder="Title" @bind="_newTitle" />
                            <input type="text" class="form-control form-control-sm mb-1"
                                   placeholder="Assignee" @bind="_newAssignee" />
                            <select class="form-select form-select-sm mb-1" @bind="_newPriority">
                                <option value="High">High</option>
                                <option value="Medium">Medium</option>
                                <option value="Low">Low</option>
                            </select>
                            <input type="date" class="form-control form-control-sm mb-1" @bind="_newDueDate" />
                            <div class="d-flex gap-1">
                                <button class="btn btn-sm btn-primary" @onclick="SaveTask">Save</button>
                                <button class="btn btn-sm btn-secondary" @onclick="CancelForm">Cancel</button>
                            </div>
                        </div>
                    </div>
                }
                else
                {
                    <button class="btn btn-sm btn-outline-primary w-100"
                            @onclick="() => ShowAddForm(column)">Add Task</button>
                }
            </div>
        }
    </div>
}

@code {
    private readonly string[] _columns = { "To Do", "In Progress", "Done" };
    private List<TaskItem> _allTasks = new();
    private List<TaskItem> _filteredTasks = new();
    private bool _loading = true;
    private string? _error;
    private string _searchTerm = string.Empty;

    // Form state
    private string? _showForm;
    private string _newTitle = string.Empty;
    private string _newAssignee = string.Empty;
    private string _newPriority = "Medium";
    private DateTime _newDueDate = DateTime.Today;

    protected override async Task OnInitializedAsync()
    {
        try
        {
            _allTasks = await TaskService.GetAllTasksAsync();
            ApplyFilter();
        }
        catch (Exception ex)
        {
            _error = $"Failed to load tasks: {ex.Message}";
        }
        finally
        {
            _loading = false;
        }
    }

    private string SearchTerm
    {
        get => _searchTerm;
        set
        {
            _searchTerm = value;
            ApplyFilter();
        }
    }

    private void ApplyFilter()
    {
        _filteredTasks = string.IsNullOrWhiteSpace(_searchTerm)
            ? _allTasks.ToList()
            : _allTasks.Where(t => t.Title.Contains(_searchTerm, StringComparison.OrdinalIgnoreCase)).ToList();
    }

    private List<TaskItem> GetColumnTasks(string status) =>
        _filteredTasks.Where(t => t.Status == status).ToList();

    private int GetColumnIndex(string column) => Array.IndexOf(_columns, column);

    private string GetPriorityClass(string priority) => priority switch
    {
        "High" => "bg-danger",
        "Medium" => "bg-warning text-dark",
        "Low" => "bg-success",
        _ => "bg-secondary"
    };

    private async Task MoveTask(TaskItem task, int direction)
    {
        var currentIndex = GetColumnIndex(task.Status);
        var newIndex = currentIndex + direction;
        if (newIndex < 0 || newIndex >= _columns.Length) return;

        var newStatus = _columns[newIndex];
        try
        {
            await TaskService.UpdateTaskStatusAsync(task.Id, newStatus);
            var index = _allTasks.FindIndex(t => t.Id == task.Id);
            if (index >= 0)
            {
                _allTasks[index] = task with { Status = newStatus };
            }
            ApplyFilter();
        }
        catch (Exception ex)
        {
            _error = $"Failed to move task: {ex.Message}";
        }
    }

    private void ShowAddForm(string column)
    {
        _showForm = column;
        _newTitle = string.Empty;
        _newAssignee = string.Empty;
        _newPriority = "Medium";
        _newDueDate = DateTime.Today;
    }

    private void CancelForm()
    {
        _showForm = null;
    }

    private async Task SaveTask()
    {
        if (string.IsNullOrWhiteSpace(_newTitle) || _showForm is null) return;

        try
        {
            var created = await TaskService.CreateTaskAsync(_newTitle, _newAssignee, _newPriority, _newDueDate);
            // CreateTaskAsync creates with default status; move to target column if needed
            if (created.Status != _showForm)
            {
                await TaskService.UpdateTaskStatusAsync(created.Id, _showForm);
                created = created with { Status = _showForm };
            }
            _allTasks.Add(created);
            ApplyFilter();
            _showForm = null;
        }
        catch (Exception ex)
        {
            _error = $"Failed to create task: {ex.Message}";
        }
    }
}

